// ── Validate & sanitize voice input ──
const body = $input.first().json.body;

const store_id = body.store_id;
const session_id = body.session_id || `voice-${store_id}-${Date.now()}`;
const message = (body.message || '').trim().slice(0, 2000);
const conversation_history = body.conversation_history || [];

if (!store_id) throw new Error('Missing required field: store_id');
if (!message) throw new Error('Missing required field: message');

// Prompt injection defense
const injectionPatterns = [
  'ignore previous instructions',
  'ignore all instructions',
  'disregard your instructions',
  'system prompt',
  'you are now',
  'jailbreak',
  'DAN mode'
];

let safeMessage = message;
injectionPatterns.forEach(pattern => {
  safeMessage = safeMessage.replace(new RegExp(pattern, 'gi'), '[removed]');
});

return [{
  json: {
    store_id,
    session_id,
    message: safeMessage,
    conversation_history
  }
}];

// ── Build pgvector RAG query ──
const embeddingResult = $('OpenAI — Embed Query').item.json;
let embedding;

if (Array.isArray(embeddingResult.data)) {
  embedding = embeddingResult.data[0].embedding;
} else if (Array.isArray(embeddingResult.embedding)) {
  embedding = embeddingResult.embedding;
} else if (embeddingResult.data && embeddingResult.data.embedding) {
  embedding = embeddingResult.data.embedding;
} else {
  embedding = embeddingResult;
}

const store_id = $('Validate Voice Input').item.json.store_id;
const aiConfig = $('Supabase — Fetch AI Config').item.json || {};
const topK = aiConfig.top_k_retrieval || 5;
const threshold = aiConfig.similarity_threshold || 0.65;

const embeddingStr = '[' + (Array.isArray(embedding) ? embedding.join(',') : '') + ']';

return [{
  json: {
    query: `SELECT id, content, metadata, 1 - (embedding <=> '${embeddingStr}'::vector) AS similarity FROM knowledge_chunks WHERE store_id = '${store_id}' AND is_active = true AND 1 - (embedding <=> '${embeddingStr}'::vector) > ${threshold} ORDER BY embedding <=> '${embeddingStr}'::vector LIMIT ${topK};`,
    store_id
  }
}];

// ── Assemble context for short voice responses ──
const userMessage = $('Validate Voice Input').item.json.message;
const storeProfile = $('Supabase — Fetch Store').item.json;
const aiConfig = $('Supabase — Fetch AI Config').item.json || {};
const chunks = $('Supabase — RAG Search').all().map(i => i.json);
const conversationHistory = $('Validate Voice Input').item.json.conversation_history || [];

const agentName = aiConfig.agent_name || storeProfile.agent_name || 'Alex';
const brandVoice = aiConfig.brand_voice || storeProfile.brand_tone || 'friendly';

// ElevenLabs voice configuration
// Store owners can set their preferred voice_id in ai_configurations
const elevenlabsVoiceId = aiConfig.elevenlabs_voice_id || '21m00Tcm4TlvDq8ikWAM'; // Default: Rachel
const elevenlabsModelId = aiConfig.elevenlabs_model_id || 'eleven_turbo_v2_5';

// Build RAG context
let ragContext = chunks.length > 0
  ? chunks.map((c, i) => `[Source ${i + 1}]: ${c.content}`).join('\n\n')
  : '[NO RELEVANT CONTEXT FOUND]';

const historyText = conversationHistory.length > 0
  ? conversationHistory.slice(-6).map(m => `${m.role === 'customer' ? 'Shopper' : 'AI'}: ${m.content}`).join('\n')
  : '';

const systemPrompt = `You are ${agentName}, a helpful AI shopping assistant for ${storeProfile.store_name}.

Your style is ${brandVoice}. This is a VOICE conversation — keep answers SHORT (2-3 sentences max).

RETRIEVED CONTEXT:
${ragContext}

${historyText ? 'RECENT CONVERSATION:\n' + historyText : ''}

RULES:
1. ONLY answer using the retrieved context above
2. If context doesn't have the answer, say "I don't have that information, but the store team can help"
3. Do NOT invent prices, stock, or policies
4. Keep answers brief — this will be spoken aloud
5. Be natural and conversational`;

return [{
  json: {
    systemPrompt,
    userMessage,
    store_id: $('Validate Voice Input').item.json.store_id,
    session_id: $('Validate Voice Input').item.json.session_id,
    agentName,
    chunk_ids: chunks.map(c => c.id),
    elevenlabs_voice_id: elevenlabsVoiceId,
    elevenlabs_model_id: elevenlabsModelId
  }
}];

// ── Parse the OpenAI native node response ──
const gptResult = $input.first().json;
const context = $('Assemble Voice Context').item.json;

let aiText = gptResult.message?.content 
  || gptResult.text 
  || gptResult.choices?.[0]?.message?.content 
  || gptResult.output 
  || 'Sorry, I had trouble generating a response.';

return [{
  json: {
    ai_response: aiText,
    message: aiText,
    transcript: context.userMessage,
    conversation_id: context.session_id,
    confidence: 0.95,
    store_id: context.store_id,
    agent_name: context.agentName,
    chunk_ids: context.chunk_ids,
    elevenlabs_voice_id: context.elevenlabs_voice_id,
    elevenlabs_model_id: context.elevenlabs_model_id
  }
}];

// ── Encode ElevenLabs audio as base64 for frontend playback ──
const binary = $input.first().binary;
const parsedResponse = $('Parse AI Response').item.json;

let audioBase64 = null;

if (binary && binary.data) {
  // n8n stores binary data - convert to base64 string
  const binaryData = binary.data;
  audioBase64 = binaryData.data || null; // Already base64 from n8n
}

return [{
  json: {
    ai_response: parsedResponse.ai_response,
    message: parsedResponse.message,
    transcript: parsedResponse.transcript,
    conversation_id: parsedResponse.conversation_id,
    confidence: parsedResponse.confidence,
    store_id: parsedResponse.store_id,
    agent_name: parsedResponse.agent_name,
    chunk_ids: parsedResponse.chunk_ids,
    audio_base64: audioBase64
  }
}];

